body.script:
//

// Toggle Search Overlay
function toggleSearch() {
  const overlay = document.getElementById('searchOverlay');
  overlay.classList.toggle('active');
  if (overlay.classList.contains('active')) {
    document.querySelector('.search-input').focus();
  }
}

// Toggle AI Chat Widget
function toggleAIChat() {
  const widget = document.getElementById('aiChatWidget');
  widget.classList.toggle('active');
  if (widget.classList.contains('active')) {
    document.getElementById('chatInput').focus();
  }
}

// Send Chat Message
function sendChatMessage() {
  const input = document.getElementById('chatInput');
  const message = input.value.trim();

  if (!message) return;

  // Add user message
  addChatMessage(message, 'user');
  input.value = '';

  // Simulate AI response (replace with actual API call)
  setTimeout(() => {
    const response = 'شكراً على رسالتك! هذه رسالة تجريبية. يجب ربط المساعد بواجهة API حقيقية.';
    addChatMessage(response, 'bot');
  }, 1000);
}

// Add Chat Message
function addChatMessage(text, sender) {
  const messagesContainer = document.getElementById('chatMessages');
  const messageDiv = document.createElement('div');
  messageDiv.className = `chat-message ${sender}`;

  const avatarDiv = document.createElement('div');
  avatarDiv.className = 'message-avatar';
  avatarDiv.innerHTML = sender === 'user' ? '<i class="fas fa-user"></i>' : '<i class="fas fa-robot"></i>';

  const contentDiv = document.createElement('div');
  contentDiv.className = 'message-content';
  contentDiv.textContent = text;

  messageDiv.appendChild(avatarDiv);
  messageDiv.appendChild(contentDiv);
  messagesContainer.appendChild(messageDiv);

  // Scroll to bottom
  messagesContainer.scrollTop = messagesContainer.scrollHeight;
}

// Handle Enter key in chat
document.addEventListener('DOMContentLoaded', function() {
  const chatInput = document.getElementById('chatInput');
  if (chatInput) {
    chatInput.addEventListener('keypress', function(e) {
      if (e.key === 'Enter') {
        sendChatMessage();
      }
    });
  }

  // Load featured books
  loadFeaturedBooks();
});

// Close search on Escape
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') {
    const searchOverlay = document.getElementById('searchOverlay');
    const chatWidget = document.getElementById('aiChatWidget');
    const pdfModal = document.getElementById('pdfReaderModal');

    if (searchOverlay.classList.contains('active')) {
      toggleSearch();
    }
    if (chatWidget.classList.contains('active')) {
      toggleAIChat();
    }
    if (pdfModal.classList.contains('active')) {
      closePDFReader();
    }
  }
});

// PDF Reader Functions
function openPDFReader(title, url) {
  const modal = document.getElementById('pdfReaderModal');
  const iframe = document.getElementById('pdfReaderIframe');
  const titleElement = document.getElementById('pdfReaderTitle');

  titleElement.textContent = title;
  iframe.src = url;
  modal.classList.add('active');
}

function closePDFReader() {
  const modal = document.getElementById('pdfReaderModal');
  const iframe = document.getElementById('pdfReaderIframe');

  modal.classList.remove('active');
  iframe.src = '';
}

// Load Featured Books (placeholder)
function loadFeaturedBooks() {
  const container = document.getElementById('featured-books-container');
  if (!container) return;

  // هذا مثال - سيتم استبداله بالقراءة من Google Sheet
  const sampleBooks = [
    {
      title: 'صحيح البخاري',
      author: 'الإمام البخاري',
      icon: 'book-quran'
    },
    {
      title: 'رياض الصالحين',
      author: 'الإمام النووي',
      icon: 'book-open'
    },
    {
      title: 'زاد المعاد',
      author: 'ابن القيم',
      icon: 'book'
    }
  ];

  container.innerHTML = sampleBooks.map(book => `
    <div class="book-item">
      <i class="fas fa-${book.icon}" style="font-size: 2rem; color: var(--accent-gold);"></i>
      <div class="book-info">
        <h4>${book.title}</h4>
        <p>${book.author}</p>
      </div>
    </div>
  `).join('');
}

// Smooth scroll for anchor links
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
  anchor.addEventListener('click', function (e) {
    const href = this.getAttribute('href');
    if (href !== '#' && href !== '') {
      e.preventDefault();
      const target = document.querySelector(href);
      if (target) {
        target.scrollIntoView({
          behavior: 'smooth',
          block: 'start'
        });
      }
    }
  });
});

//
